            magicBytes[4] == (byte)0x0D && magicBytes[5] == (byte)0x0A && 
            magicBytes[6] == (byte)0x1A && magicBytes[7] == (byte)0x0A) {
            return "PNG";
        }
        // Check GIF (47 49 46)
        if (bytesRead >= 3 && magicBytes[0] == (byte)0x47 && magicBytes[1] == (byte)0x49 && magicBytes[2] == (byte)0x46) {
            return "GIF";
        }
        // Check BMP (42 4D)
        if (bytesRead >= 2 && magicBytes[0] == (byte)0x42 && magicBytes[1] == (byte)0x4D) {
            return "BMP";
        }
        // Check WEBP (RIFF header with WEBP: 52 49 46 46 followed by ... 57 45 42 50)
        if (bytesRead >= 12 && magicBytes[0] == (byte)0x52 && magicBytes[1] == (byte)0x49 && 
            magicBytes[2] == (byte)0x46 && magicBytes[3] == (byte)0x46 && 
            magicBytes[8] == (byte)0x57 && magicBytes[9] == (byte)0x45 && 
            magicBytes[10] == (byte)0x42 && magicBytes[11] == (byte)0x50) {
